/*
 * Feistel Network Block Cipher - C Implementation
 * Educational demonstration of Feistel structure principles
 */

#include <stdio.h>
#include <stdint.h>

#define BLOCK_SIZE 16 // 16-bit blocks
#define NUM_ROUNDS 4

// Global S-box (4x16 for demonstration)
const uint8_t s_box[4][16] = {
 {14, 4, 13, 1, 2, 15, 11, 8, 3, 10, 6, 12, 5, 9, 0, 7},
 {0, 15, 7, 4, 14, 2, 13, 1, 10, 6, 12, 11, 9, 5, 3, 8},
 {4, 1, 14, 8, 13, 6, 2, 11, 15, 12, 9, 7, 3, 10, 5, 0},
 {15, 12, 2, 13, 9, 0, 7, 11, 4, 8, 1, 10, 6, 3, 5, 14}
};

// Round keys (simplified generation)
uint8_t round_keys[NUM_ROUNDS];

/*
 * Generate round keys from main key
 */
void key_schedule(uint16_t key) {
 for (int i = 0; i < NUM_ROUNDS; i++) {
 // Simple key schedule: rotate and extract
 round_keys[i] = (key >> i) | (key << (8 - i));
 }
}

/*
 * Expansion permutation - expands 8 bits to more for S-box input
 */
uint16_t expand_permute(uint8_t right) {
 // Expansion permutation E (8 to 12 bits)
 static const uint8_t e_box[8] = {0, 1, 2, 3, 2, 3, 4, 5};

 uint16_t expanded = 0;
 for (int i = 0; i < 8; i++) {
 if (right & (1 << (7 - i))) {
 expanded |= (1 << e_box[i]);
 }
 }
 return expanded;
}

/*
 * F Function - the core of Feistel network
 * Input: right half (8 bits), round key (8 bits)
 * Output: 8-bit transformed value
 */
uint8_t f_function(uint8_t right, uint8_t round_key) {
 // 1. Expansion permutation
 uint16_t expanded = expand_permute(right);

 // 2. XOR with round key (expanded to match)
 uint16_t xored = expanded ^ ((round_key << 4) & 0xFF0);

 // 3. S-box substitution (split into 4 groups of 3 bits)
 uint8_t result = 0;
 for (int i = 0; i < 4; i++) {
 uint8_t nibble = (xored >> (i * 3)) & 0x07;
 uint8_t substituted = s_box[i][nibble];
 result |= (substituted << (i * 2));
 }

 return result & 0xFF;
}

/*
 * Encrypt using Feistel Network
 * Input: 16-bit plaintext
 * Output: 16-bit ciphertext
 */
uint16_t feistel_encrypt(uint16_t plaintext) {
 // Split into left and right halves (8 bits each)
 uint8_t left = (plaintext >> 8) & 0xFF;
 uint8_t right = plaintext & 0xFF;

 // Feistel rounds
 for (int round = 0; round < NUM_ROUNDS; round++) {
 uint8_t new_right;

 // Save current right for next iteration
 uint8_t temp = right;

 // Compute new right: left XOR F(right, key)
 new_right = left ^ f_function(right, round_keys[round]);

 // New left is old right
 left = temp;
 right = new_right;
 }

 // Combine halves (final swap is part of structure)
 uint16_t ciphertext = ((uint16_t)right << 8) | left;
 return ciphertext;
}

/*
 * Decrypt using Feistel Network
 * Same structure, just reversed keys!
 */
uint16_t feistel_decrypt(uint16_t ciphertext) {
 // Split into left and right halves
 uint8_t left = (ciphertext >> 8) & 0xFF;
 uint8_t right = ciphertext & 0xFF;

 // Feistel rounds with reversed keys
 for (int round = NUM_ROUNDS - 1; round >= 0; round--) {
 uint8_t new_right;
 uint8_t temp = right;

 new_right = left ^ f_function(right, round_keys[round]);
 left = temp;
 right = new_right;
 }

 uint16_t plaintext = ((uint16_t)right << 8) | left;
 return plaintext;
}

/*
 * Print binary representation
 */
void print_binary(uint16_t value, int bits) {
 for (int i = bits - 1; i >= 0; i--) {
 printf("%d", (value >> i) & 1);
 }
}

/*
 * Demonstrate avalanche effect
 */
void test_avalanche(uint16_t key, uint16_t pt1, uint16_t pt2) {
 key_schedule(key);

 uint16_t ct1 = feistel_encrypt(pt1);
 uint16_t ct2 = feistel_encrypt(pt2);

 uint16_t diff = ct1 ^ ct2;
 int bit_diff = 0;
 for (int i = 0; i < 16; i++) {
 if (diff & (1 << i)) bit_diff++;
 }

 printf("\nAvalanche Effect Test:\n");
 printf(" Input 1: "); print_binary(pt1, 16); printf("\n");
 printf(" Input 2: "); print_binary(pt2, 16); printf("\n");
 printf(" Output 1: "); print_binary(ct1, 16); printf("\n");
 printf(" Output 2: "); print_binary(ct2, 16); printf("\n");
 printf(" Bit differences: %d/16\n", bit_diff);
}

/*
 * Main function - demonstrate Feistel cipher
 */
int main() {
 uint16_t key = 0x1A2B; // 16-bit key

 printf("=== Feistel Network Block Cipher ===\n\n");

 // Initialize round keys
 key_schedule(key);

 // Test encryption/decryption
 uint16_t plaintext = 0xABCD;

 printf("Original plaintext: 0x%04X\n", plaintext);

 uint16_t ciphertext = feistel_encrypt(plaintext);
 printf("Encrypted ciphertext: 0x%04X\n", ciphertext);

 uint16_t decrypted = feistel_decrypt(ciphertext);
 printf("Decrypted plaintext: 0x%04X\n", decrypted);

 printf("\nVerification: %s\n", 
 (plaintext == decrypted) ? "SUCCESS" : "FAILED");

 // Test avalanche effect (1-bit change in input)
 test_avalanche(key, 0x0000, 0x0001);

 // Additional test cases
 printf("\nAdditional Tests:\n");
 uint16_t test_cases[] = {0x0000, 0x1234, 0xFFFF, 0x5555};

 for (int i = 0; i < 4; i++) {
 uint16_t pt = test_cases[i];
 uint16_t ct = feistel_encrypt(pt);
 uint16_t dec = feistel_decrypt(ct);
 printf(" 0x%04X -> 0x%04X -> 0x%04X %s\n", 
 pt, ct, dec, (pt == dec) ? "OK" : "FAIL");
 }

 return 0;
}
